class DynamicArray:
    def __init__(self, capacity=1):
        self.size = 0
        self.capacity = capacity
        self.array = [None] * capacity

    def append(self, element):
        if self.size == self.capacity:
            self._resize(2 * self.capacity)
        self.array[self.size] = element
        self.size += 1

    def _resize(self, new_capacity):
        new_array = [None] * new_capacity
        for i in range(self.size):
            new_array[i] = self.array[i]
        self.array = new_array
        self.capacity = new_capacity

    def __len__(self):
        return self.size

    def __getitem__(self, index):
        if 0 <= index < self.size:
            return self.array[index]
        raise IndexError("Index out of range")

#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *data;
    int size;
    int capacity;
} DynamicArray;

void initArray(DynamicArray *arr, int initialCap) {
    arr->capacity = initialCap;
    arr->size = 0;
    arr->data = (int*)malloc(initialCap * sizeof(int));
}

void pushBack(DynamicArray *arr, int element) {
    if (arr->size == arr->capacity) {
        arr->capacity *= 2;
        arr->data = (int*)realloc(arr->data, arr->capacity * sizeof(int));
    }
    arr->data[arr->size++] = element;
}

void shrinkToFit(DynamicArray *arr) {
    if (arr->size < arr->capacity / 4 && arr->size > 0) {
        arr->capacity = arr->size;
        arr->data = (int*)realloc(arr->data, arr->capacity * sizeof(int));
    }
}

void freeArray(DynamicArray *arr) {
    free(arr->data);
    arr->data = NULL;
}

import java.util.ArrayList;
import java.util.List;

public class DynamicArrayDemo {
    public static void main(String[] args) {
        // Using ArrayList - Java's dynamic array implementation
        List<Integer> dynamicList = new ArrayList<>();

        // Add elements - automatically resizes
        for (int i = 1; i <= 20; i++) {
            dynamicList.add(i);
            System.out.println("Size: " + dynamicList.size() + 
                             ", Capacity: " + 
                             ((ArrayList<?>)dynamicList).getClass()
                             .getDeclaredField("elementData").getType());
        }

        // Access by index - O(1)
        int element = dynamicList.get(5);  // O(1)

        // Insert at end - O(1) amortized
        dynamicList.add(100);

        // Remove from end - O(1) amortized
        dynamicList.remove(dynamicList.size() - 1);

        // Note: ArrayList grows by 50% (1.5x) when full
        // Initial capacity is 10
    }
}
